import React, { useState } from 'react';

export default function PricingGrid({ plans }) {
  const [isAnnual, setIsAnnual] = useState(false);

  return (
    <div className="max-w-5xl mx-auto py-10 px-4 font-sans flex flex-col items-center">
      {/* Toggle Selector */}
      <div className="flex items-center bg-gray-100 p-1.5 rounded-xl mb-10 border border-gray-200">
        <button
          onClick={() => setIsAnnual(false)}
          className={`px-4 py-2 text-sm font-semibold rounded-lg transition ${!isAnnual ? 'bg-white text-purple-700 shadow-sm' : 'text-gray-500 hover:text-gray-800'}`}
        >
          Monthly
        </button>
        <button
          onClick={() => setIsAnnual(true)}
          className={`px-4 py-2 text-sm font-semibold rounded-lg transition flex items-center gap-1.5 ${isAnnual ? 'bg-white text-purple-700 shadow-sm' : 'text-gray-500 hover:text-gray-800'}`}
        >
          <span>Annually</span>
          <span className="text-[10px] bg-purple-100 text-purple-700 px-1.5 py-0.5 rounded-full uppercase">Save 20%</span>
        </button>
      </div>

      {/* Grid Layout */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-8 w-full">
        {plans.map((plan, idx) => {
          const rawPrice = plan.price;
          const price = isAnnual ? Math.round(rawPrice * 12 * 0.8) : rawPrice;
          const billingLabel = isAnnual ? "/ year" : "/ mo";

          return (
            <div
              key={idx}
              className={`border rounded-2xl p-6 flex flex-col justify-between transition-all duration-300 relative ${
                plan.isPopular
                  ? 'border-purple-500 ring-2 ring-purple-200 shadow-lg scale-105 z-10 bg-white'
                  : 'border-gray-200 bg-white hover:border-gray-300'
              }`}
            >
              {plan.isPopular && (
                <span className="absolute -top-3 left-1/2 -translate-x-1/2 bg-purple-500 text-white text-[10px] font-bold uppercase tracking-widest px-3 py-1 rounded-full">
                  Most Popular
                </span>
              )}

              <div>
                <h3 className="font-bold text-gray-800 text-lg uppercase tracking-wider">{plan.name}</h3>
                <p className="text-gray-400 text-xs mt-1">{plan.tagline}</p>

                <div className="my-6">
                  <span className="text-4xl font-bold text-gray-800">${price}</span>
                  <span className="text-gray-400 text-sm">{billingLabel}</span>
                </div>

                <ul className="flex flex-col gap-3">
                  {plan.features.map((feat, fIdx) => (
                    <li key={fIdx} className="flex items-center gap-2.5 text-sm text-gray-600">
                      <svg className={`w-4 h-4 shrink-0 ${plan.isPopular ? 'text-purple-500' : 'text-green-500'}`} fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2.5}>
                        <path strokeLinecap="round" strokeLinejoin="round" d="M5 13l4 4L19 7" />
                      </svg>
                      <span>{feat}</span>
                    </li>
                  ))}
                </ul>
              </div>

              <button className={`w-full py-2.5 rounded-xl font-semibold mt-8 border transition text-sm ${
                plan.isPopular
                  ? 'bg-purple-600 hover:bg-purple-700 text-white border-transparent'
                  : 'bg-white hover:bg-gray-50 border-gray-300 text-gray-700'
              }`}>
                Choose {plan.name}
              </button>
            </div>
          );
        })}
      </div>
    </div>
  );
}
